const competitors = [
  { name: 'Tekmetric', domain: 'tekmetric.com', pricingUrl: 'https://www.tekmetric.com/pricing', blogUrl: 'https://www.tekmetric.com/blog' },
  { name: 'Shop-Ware', domain: 'shop-ware.com', pricingUrl: 'https://www.shop-ware.com/pricing', blogUrl: 'https://www.shop-ware.com/blog' },
  { name: 'AutoLeap', domain: 'autoleap.com', pricingUrl: 'https://www.autoleap.com/pricing', blogUrl: 'https://www.autoleap.com/blog' },
  { name: 'Mitchell 1', domain: 'mitchell1.com', pricingUrl: 'https://www.mitchell1.com/shop-management', blogUrl: 'https://www.mitchell1.com/news' }
];
return competitors.map(c => ({ json: c }));

const competitor = $('Define Competitors').item.json;
const pricingResponse = $('Fetch Pricing Page').item.json;
const reviewResponse = $('Check Reviews via SerpAPI').item.json;
const blogResponse = $('Fetch Blog Page').item.json;

// Extract pricing info (look for dollar signs and plan names in raw HTML)
const pricingHtml = typeof pricingResponse === 'string' ? pricingResponse : (pricingResponse.data || pricingResponse.body || '');
const priceMatches = (typeof pricingHtml === 'string') ? pricingHtml.match(/\$[\d,]+(?:\.\d{2})?(?:\/mo|per month|month)?/gi) || [] : [];
const pricingStatus = pricingResponse.statusCode === 200 ? 'accessible' : 'blocked_or_error';

// Extract review snippets from SerpAPI results
const organicResults = reviewResponse.organic_results || [];
const reviewSnippets = organicResults.slice(0, 5).map(r => ({
  title: r.title || '',
  snippet: r.snippet || '',
  link: r.link || ''
}));

// Check if blog has recent posts (look for dates in HTML)
const blogHtml = typeof blogResponse === 'string' ? blogResponse : (blogResponse.data || blogResponse.body || '');
const blogStatus = blogResponse.statusCode === 200 ? 'accessible' : 'blocked_or_error';

return [{
  json: {
    competitor: competitor.name,
    domain: competitor.domain,
    pricing: {
      status: pricingStatus,
      detected_prices: priceMatches.slice(0, 10)
    },
    reviews: reviewSnippets,
    blog: {
      status: blogStatus
    }
  }
}];

const allIntel = $('Parse Competitor Intel').all().map(i => i.json);
const date = $now.toFormat('yyyy-MM-dd');

let report = `# Competitive Intelligence Report - BayFlow - ${date}\n\n`;

let hasSignificant = false;

for (const comp of allIntel) {
  report += `## ${comp.competitor} (${comp.domain})\n\n`;

  // Pricing
  report += `### Pricing\n`;
  report += `- Page status: ${comp.pricing.status}\n`;
  if (comp.pricing.detected_prices.length > 0) {
    report += `- Detected prices: ${comp.pricing.detected_prices.join(', ')}\n`;
  } else {
    report += `- No prices detected (may use custom quoting)\n`;
  }
  report += `\n`;

  // Reviews
  report += `### Recent Review Mentions\n`;
  if (comp.reviews.length > 0) {
    for (const r of comp.reviews) {
      report += `- **${r.title}**: ${r.snippet}\n`;
    }
  } else {
    report += `- No review data found\n`;
  }
  report += `\n`;

  // Blog
  report += `### Blog\n`;
  report += `- Status: ${comp.blog.status}\n`;
  report += `\n---\n\n`;
}

report += `*Generated by Competitor Monitor at ${new Date().toISOString()}*\n`;

// Flag significant if any pricing page became accessible/blocked
for (const comp of allIntel) {
  if (comp.pricing.detected_prices.length > 0) hasSignificant = true;
}

return [{ json: { report, date, hasSignificant, competitorCount: allIntel.length } }];
